SELECT post_id, version_num, base_version, is_base, patch_hash, chunk_hash, request_id, create_time
FROM content_revision
WHERE post_id = #{postId} AND version_num = #{versionNum}

SELECT post_id, version_num, base_version, is_base, patch_hash, chunk_hash, request_id, create_time
FROM content_revision
WHERE post_id = #{postId}
ORDER BY version_num DESC

    LIMIT #{limit}


    OFFSET #{offset}
